-- Insert 50 distance-jump exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Snap Down to Stick', 'distance-jump-snap-down-to-stick', 'Snap Down to Stick addresses distance-jumping performance by targeting teaches fast postural organization into a quiet athletic landing before longer jumps are loaded. It should be coached with clear quality gates, honest phase placement, and enough recovery to preserve the intended adaptation.', 'BEGINNER', 8, 2, 4, 20, 45, 70, 'Snap Down to Stick is a Resilience drill for jumping athletes who need more horizontal distance. Teaches fast postural organization into a quiet athletic landing before longer jumps are loaded.', 'Primary subrole: landing_braking_control. Coach Snap Down to Stick for distance-jump transfer: projection, stiffness, rhythm, tissue capacity, or landing control according to the drill. Keep the dose aligned with Resilience intent.', 'Move with intent, own the position, and make every rep look like the one you want to keep.', 'Landing and braking control', 'resilience', 'landing_braking_control', 'snap_down_to_stick', '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","ankle_dorsiflexion_plantarflexion"],"primary_tissues":["calves","quadriceps","glutes","hamstrings","foot_intrinsics"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":null,"balance_demand":"moderate","coordination_demand":"moderate","impact_level":2,"range_of_motion":"Use the largest pain-free range that preserves posture, foot pressure, and alignment.","surface_and_space":"Clear lane with safe stopping and reset space; avoid slick, crowded, or excessively hard surfaces for impact work.","asymmetry_watch":"Watch for side-to-side differences in foot pressure, knee tracking, hip height, trunk rotation, arm timing, and confidence."}'::jsonb, '{"movement_description":"Perform Snap Down to Stick as a quality-first distance-jump support drill, emphasizing the specific constraint named in the card summary.","setup":["Set a clear lane and landing target for Snap Down to Stick; use none as needed.","Give the athlete enough space to land, stick, and step out safely.","Start with the lower-amplitude version and confirm quiet landings before adding distance or speed."],"execution_steps":["Start tall or from the assigned low box/entry position.","Move into the landing task with controlled intent.","Land through the midfoot with knees tracking over toes and hips back enough to absorb force.","Freeze for two seconds, breathe, and reset before the next attempt."],"coach_cues":["Quiet feet","Knee over middle toes","Hips level","Own the stick","Breathe before you move"],"common_faults":["Knee dives inward","Heel or toe lifts excessively","Trunk folds or twists","Athlete steps out before owning the stick","Landing noise increases"],"breathing_cues":["Exhale softly to find ribs before the set.","Do not hold the breath through low-level skill work unless bracing under load requires a brief brace.","Reset breathing between high-intent attempts."],"quality_gate":["The athlete can explain the goal of the drill in simple language.","Landing/contact sound, posture, and alignment remain repeatable.","Speed, height, distance, release velocity, or rhythm does not visibly drop across the set."],"stop_signs":["Pain, sharp discomfort, loss of confidence, dizziness, or symptom response appears.","Landing becomes loud, uncontrolled, or misaligned for two reps in a row.","The athlete begins racing the drill, guessing, or turning it into conditioning.","Output speed, distance, stiffness, rhythm, or release quality clearly falls."]}'::jsonb),
  ('Drop Landing to Stick', 'distance-jump-drop-landing-to-stick', 'Drop Landing to Stick addresses distance-jumping performance by targeting builds landing tolerance and braking posture from a slightly higher entry without turning it into a jump workout. It should be coached with clear quality gates, honest phase placement, and enough recovery to preserve the intended adaptation.', 'BEGINNER', 8, 2, 4, 20, 45, 70, 'Drop Landing to Stick is a Resilience drill for jumping athletes who need more horizontal distance. Builds landing tolerance and braking posture from a slightly higher entry without turning it into a jump workout.', 'Primary subrole: landing_braking_control. Coach Drop Landing to Stick for distance-jump transfer: projection, stiffness, rhythm, tissue capacity, or landing control according to the drill. Keep the dose aligned with Resilience intent.', 'Move with intent, own the position, and make every rep look like the one you want to keep.', 'Drop landing control', 'resilience', 'landing_braking_control', 'drop_landing_to_stick', '{"primary_joint_actions":["hip_flexion","knee_flexion","ankle_dorsiflexion"],"primary_tissues":["calves","quadriceps","glutes","tendons"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":null,"balance_demand":"moderate","coordination_demand":"moderate","impact_level":3,"range_of_motion":"Use the largest pain-free range that preserves posture, foot pressure, and alignment.","surface_and_space":"Clear lane with safe stopping and reset space; avoid slick, crowded, or excessively hard surfaces for impact work.","asymmetry_watch":"Watch for side-to-side differences in foot pressure, knee tracking, hip height, trunk rotation, arm timing, and confidence."}'::jsonb, '{"movement_description":"Perform Drop Landing to Stick as a quality-first distance-jump support drill, emphasizing the specific constraint named in the card summary.","setup":["Set a clear lane and landing target for Drop Landing to Stick; use low box as needed.","Give the athlete enough space to land, stick, and step out safely.","Start with the lower-amplitude version and confirm quiet landings before adding distance or speed."],"execution_steps":["Start tall or from the assigned low box/entry position.","Move into the landing task with controlled intent.","Land through the midfoot with knees tracking over toes and hips back enough to absorb force.","Freeze for two seconds, breathe, and reset before the next attempt."],"coach_cues":["Quiet feet","Knee over middle toes","Hips level","Own the stick","Breathe before you move"],"common_faults":["Knee dives inward","Heel or toe lifts excessively","Trunk folds or twists","Athlete steps out before owning the stick","Landing noise increases"],"breathing_cues":["Exhale softly to find ribs before the set.","Do not hold the breath through low-level skill work unless bracing under load requires a brief brace.","Reset breathing between high-intent attempts."],"quality_gate":["The athlete can explain the goal of the drill in simple language.","Landing/contact sound, posture, and alignment remain repeatable.","Speed, height, distance, release velocity, or rhythm does not visibly drop across the set."],"stop_signs":["Pain, sharp discomfort, loss of confidence, dizziness, or symptom response appears.","Landing becomes loud, uncontrolled, or misaligned for two reps in a row.","The athlete begins racing the drill, guessing, or turning it into conditioning.","Output speed, distance, stiffness, rhythm, or release quality clearly falls."]}'::jsonb),
  ('Single-Leg Landing Stick', 'single-leg-landing-stick', 'Single-Leg Landing Stick addresses distance-jumping performance by targeting builds unilateral landing ownership so takeoff and landing forces do not collapse through the hip, knee, or foot. It should be coached with clear quality gates, honest phase placement, and enough recovery to preserve the intended adaptation.', 'BEGINNER', 8, 2, 4, 20, 45, 70, 'Single-Leg Landing Stick is a Resilience drill for jumping athletes who need more horizontal distance. Builds unilateral landing ownership so takeoff and landing forces do not collapse through the hip, knee, or foot.', 'Primary subrole: single_leg_balance_foot_ankle_hip_control. Coach Single-Leg Landing Stick for distance-jump transfer: projection, stiffness, rhythm, tissue capacity, or landing control according to the drill. Keep the dose aligned with Resilience intent.', 'Move with intent, own the position, and make every rep look like the one you want to keep.', 'Single-leg landing control', 'resilience', 'single_leg_balance_foot_ankle_hip_control', 'single_leg_landing_stick', '{"primary_joint_actions":["single_leg_hip_knee_ankle_alignment","frontal_plane_control"],"primary_tissues":["glute_medius","calves","quadriceps","foot_intrinsics"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":null,"balance_demand":"high","coordination_demand":"moderate","impact_level":3,"range_of_motion":"Use the largest pain-free range that preserves posture, foot pressure, and alignment.","surface_and_space":"Clear lane with safe stopping and reset space; avoid slick, crowded, or excessively hard surfaces for impact work.","asymmetry_watch":"Watch for side-to-side differences in foot pressure, knee tracking, hip height, trunk rotation, arm timing, and confidence."}'::jsonb, '{"movement_description":"Perform Single-Leg Landing Stick as a quality-first distance-jump support drill, emphasizing the specific constraint named in the card summary.","setup":["Set a clear lane and landing target for Single-Leg Landing Stick; use none as needed.","Give the athlete enough space to land, stick, and step out safely.","Start with the lower-amplitude version and confirm quiet landings before adding distance or speed."],"execution_steps":["Start tall or from the assigned low box/entry position.","Move into the landing task with controlled intent.","Land through the midfoot with knees tracking over toes and hips back enough to absorb force.","Freeze for two seconds, breathe, and reset before the next attempt."],"coach_cues":["Quiet feet","Knee over middle toes","Hips level","Own the stick","Breathe before you move"],"common_faults":["Knee dives inward","Heel or toe lifts excessively","Trunk folds or twists","Athlete steps out before owning the stick","Landing noise increases"],"breathing_cues":["Exhale softly to find ribs before the set.","Do not hold the breath through low-level skill work unless bracing under load requires a brief brace.","Reset breathing between high-intent attempts."],"quality_gate":["The athlete can explain the goal of the drill in simple language.","Landing/contact sound, posture, and alignment remain repeatable.","Speed, height, distance, release velocity, or rhythm does not visibly drop across the set."],"stop_signs":["Pain, sharp discomfort, loss of confidence, dizziness, or symptom response appears.","Landing becomes loud, uncontrolled, or misaligned for two reps in a row.","The athlete begins racing the drill, guessing, or turning it into conditioning.","Output speed, distance, stiffness, rhythm, or release quality clearly falls."]}'::jsonb),
  ('Low Box Step-Off to Horizontal Stick', 'low-box-step-off-to-horizontal-stick', 'Low Box Step-Off to Horizontal Stick addresses distance-jumping performance by targeting adds a small forward travel demand so athletes learn to absorb horizontal momentum cleanly. It should be coached with clear quality gates, honest phase placement, and enough recovery to preserve the intended adaptation.', 'BEGINNER', 8, 2, 4, 20, 45, 70, 'Low Box Step-Off to Horizontal Stick is a Resilience drill for jumping athletes who need more horizontal distance. Adds a small forward travel demand so athletes learn to absorb horizontal momentum cleanly.', 'Primary subrole: landing_braking_control. Coach Low Box Step-Off to Horizontal Stick for distance-jump transfer: projection, stiffness, rhythm, tissue capacity, or landing control according to the drill. Keep the dose aligned with Resilience intent.', 'Move with intent, own the position, and make every rep look like the one you want to keep.', 'Horizontal landing control', 'resilience', 'landing_braking_control', 'low_box_step_off_to_horizontal_stick', '{"primary_joint_actions":["hip_hinge","knee_flexion","ankle_dorsiflexion"],"primary_tissues":["calves","quadriceps","glutes","hamstrings"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":null,"balance_demand":"moderate","coordination_demand":"moderate","impact_level":3,"range_of_motion":"Use the largest pain-free range that preserves posture, foot pressure, and alignment.","surface_and_space":"Clear lane with safe stopping and reset space; avoid slick, crowded, or excessively hard surfaces for impact work.","asymmetry_watch":"Watch for side-to-side differences in foot pressure, knee tracking, hip height, trunk rotation, arm timing, and confidence."}'::jsonb, '{"movement_description":"Perform Low Box Step-Off to Horizontal Stick as a quality-first distance-jump support drill, emphasizing the specific constraint named in the card summary.","setup":["Set a clear lane and landing target for Low Box Step-Off to Horizontal Stick; use low box as needed.","Give the athlete enough space to land, stick, and step out safely.","Start with the lower-amplitude version and confirm quiet landings before adding distance or speed."],"execution_steps":["Start tall or from the assigned low box/entry position.","Move into the landing task with controlled intent.","Land through the midfoot with knees tracking over toes and hips back enough to absorb force.","Freeze for two seconds, breathe, and reset before the next attempt."],"coach_cues":["Quiet feet","Knee over middle toes","Hips level","Own the stick","Breathe before you move"],"common_faults":["Knee dives inward","Heel or toe lifts excessively","Trunk folds or twists","Athlete steps out before owning the stick","Landing noise increases"],"breathing_cues":["Exhale softly to find ribs before the set.","Do not hold the breath through low-level skill work unless bracing under load requires a brief brace.","Reset breathing between high-intent attempts."],"quality_gate":["The athlete can explain the goal of the drill in simple language.","Landing/contact sound, posture, and alignment remain repeatable.","Speed, height, distance, release velocity, or rhythm does not visibly drop across the set."],"stop_signs":["Pain, sharp discomfort, loss of confidence, dizziness, or symptom response appears.","Landing becomes loud, uncontrolled, or misaligned for two reps in a row.","The athlete begins racing the drill, guessing, or turning it into conditioning.","Output speed, distance, stiffness, rhythm, or release quality clearly falls."]}'::jsonb),
  ('Ankle Pogo in Place', 'distance-jump-ankle-pogo-in-place', 'Ankle Pogo in Place addresses distance-jumping performance by targeting low-amplitude elastic contact drill that teaches springy stiffness without large jump stress. It should be coached with clear quality gates, honest phase placement, and enough recovery to preserve the intended adaptation.', 'INTERMEDIATE', 8, 3, 20, 15, 60, 75, 'Ankle Pogo in Place is a Output drill for jumping athletes who need more horizontal distance. Low-amplitude elastic contact drill that teaches springy stiffness without large jump stress.', 'Primary subrole: elastic_stiffness_plyometric_rudiments. Coach Ankle Pogo in Place for distance-jump transfer: projection, stiffness, rhythm, tissue capacity, or landing control according to the drill. Keep the dose aligned with Output intent.', 'Move with intent, own the position, and make every rep look like the one you want to keep.', 'Foot-ankle elastic rudiment', 'output', 'elastic_stiffness_plyometric_rudiments', 'ankle_pogo_in_place', '{"primary_joint_actions":["ankle_stiffness","forefoot_contact"],"primary_tissues":["achilles_tendon","soleus","gastrocnemius","foot_intrinsics"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":null,"balance_demand":"low_to_moderate","coordination_demand":"high","impact_level":2,"range_of_motion":"Use the largest pain-free range that preserves posture, foot pressure, and alignment.","surface_and_space":"Clear lane with safe stopping and reset space; avoid slick, crowded, or excessively hard surfaces for impact work.","asymmetry_watch":"Watch for side-to-side differences in foot pressure, knee tracking, hip height, trunk rotation, arm timing, and confidence."}'::jsonb, '{"movement_description":"Perform Ankle Pogo in Place as a quality-first distance-jump support drill, emphasizing the specific constraint named in the card summary.","setup":["Mark a straight lane or contact zone for Ankle Pogo in Place; keep the surface flat